import{c as n,Q as a,j as e,m as l}from"./chunks/framework.CQqJojvj.js";const u=JSON.parse('{"title":"12 - 场景设计题","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/12-scenarios.md","filePath":"bagu/12-scenarios.md","lastUpdated":null}'),p={name:"bagu/12-scenarios.md"};function t(i,s,r,o,c,d){return a(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="_12-场景设计题" tabindex="-1">12 - 场景设计题 <a class="header-anchor" href="#_12-场景设计题" aria-label="Permalink to &quot;12 - 场景设计题&quot;">​</a></h1><blockquote><p>场景题考察系统设计能力和技术广度的综合运用。没有标准答案，关键是展现分析思路和权衡能力。</p></blockquote><hr><h2 id="_1-如何与外部合作方交互防止被拖垮" tabindex="-1">1. 如何与外部合作方交互防止被拖垮？ <a class="header-anchor" href="#_1-如何与外部合作方交互防止被拖垮" aria-label="Permalink to &quot;1. 如何与外部合作方交互防止被拖垮？&quot;">​</a></h2><p><strong>核心策略：隔离 + 熔断 + 降级 + 限流。</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│               我方服务                            │</span></span>
<span class="line"><span>│  ┌──────────┐  ┌──────────┐  ┌──────────────┐  │</span></span>
<span class="line"><span>│  │  限流器   │  │  熔断器   │  │  降级逻辑     │  │</span></span>
<span class="line"><span>│  └─────┬────┘  └─────┬────┘  └──────┬───────┘  │</span></span>
<span class="line"><span>│        │              │              │          │</span></span>
<span class="line"><span>│        ▼              ▼              ▼          │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│  │              线程池隔离                    │   │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────┘   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                         │</span></span>
<span class="line"><span>                         ▼</span></span>
<span class="line"><span>              ┌──────────────────┐</span></span>
<span class="line"><span>              │   外部合作方服务   │</span></span>
<span class="line"><span>              └──────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p><strong>具体措施：</strong></p><ol><li><strong>线程池隔离</strong> — 为外部调用分配独立的线程池，不共享主业务线程池</li><li><strong>超时控制</strong> — 设置合理的 connectTimeout + readTimeout（如连接 2s，读取 5s）</li><li><strong>熔断保护</strong> — 用 Hystrix/Sentinel，失败率超过阈值时熔断，快速失败</li><li><strong>降级策略</strong> — 外部服务不可用时返回默认值/缓存数据/空列表</li><li><strong>限流</strong> — 对调用外部服务的接口做 QPS 限制</li><li><strong>异步解耦</strong> — 非关键路径的调用通过 MQ 异步处理</li></ol><hr><h2 id="_2-如何实现-a-网站登录后-b-网站自动登录-单点登录-sso" tabindex="-1">2. 如何实现 A 网站登录后 B 网站自动登录？（单点登录 SSO） <a class="header-anchor" href="#_2-如何实现-a-网站登录后-b-网站自动登录-单点登录-sso" aria-label="Permalink to &quot;2. 如何实现 A 网站登录后 B 网站自动登录？（单点登录 SSO）&quot;">​</a></h2><p><strong>方案一：JWT + 同域名 Cookie</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. A 登录 → 认证中心验证 → 返回 JWT → 种在顶级域名的 Cookie (.example.com)</span></span>
<span class="line"><span>2. B 请求携带该 Cookie → B 后端解密 JWT 验证 → 获取用户信息自动登录</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>方案二：CAS 协议（经典 SSO）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 用户访问 A → 重定向到认证中心（/login?service=A）</span></span>
<span class="line"><span>2. 认证中心验证用户 → 签发 TGT(全局会话) + ST(服务票据)</span></span>
<span class="line"><span>3. 重定向回 A，携带 ST</span></span>
<span class="line"><span>4. A 后端拿 ST 去认证中心验证 → 验证通过则登录</span></span>
<span class="line"><span>5. 用户访问 B → 重定向到认证中心（已有 TGT）→ 直接签发 ST 跳回 B</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>方案三：OAuth 2.0 / OIDC</strong></p><p>主要用在第三方登录（微信/Google 登录），适合跨公司授权场景。</p><hr><h2 id="_3-如何预估接口上线后的-qps" tabindex="-1">3. 如何预估接口上线后的 QPS？ <a class="header-anchor" href="#_3-如何预估接口上线后的-qps" aria-label="Permalink to &quot;3. 如何预估接口上线后的 QPS？&quot;">​</a></h2><p><strong>方法一：根据 DAU 估算</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>QPS = DAU × 人均请求次数 ÷ (活跃小时数 × 3600) × 峰值系数</span></span>
<span class="line"><span></span></span>
<span class="line"><span>例：</span></span>
<span class="line"><span>  DAU = 10万</span></span>
<span class="line"><span>  人均请求 = 20次</span></span>
<span class="line"><span>  活跃时段 = 8小时</span></span>
<span class="line"><span>  峰值系数 = 3（晚间高峰是均值的 3 倍）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  QPS ≈ 100000 × 20 ÷ (8 × 3600) × 3 ≈ 208 QPS</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>方法二：根据已有业务量推断</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新接口 QPS = 关联接口 QPS × 调用比例</span></span>
<span class="line"><span></span></span>
<span class="line"><span>例：下单接口的 QPS 约 = 商品详情页 QPS × 转化率</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>方法三：压力测试（最准确）</strong></p><p>上线前在预发布环境（或低峰期生产环境）做压测，逐步增加并发数，找到 QPS 拐点。</p><hr><h2 id="_4-订单到期关闭如何实现" tabindex="-1">4. 订单到期关闭如何实现？ <a class="header-anchor" href="#_4-订单到期关闭如何实现" aria-label="Permalink to &quot;4. 订单到期关闭如何实现？&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方案</th><th style="text-align:left;">原理</th><th style="text-align:left;">优点</th><th style="text-align:left;">缺点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>延迟队列</strong></td><td style="text-align:left;">RocketMQ 延时消息 / RabbitMQ 死信队列</td><td style="text-align:left;">可靠，生产级</td><td style="text-align:left;">依赖 MQ</td></tr><tr><td style="text-align:left;"><strong>Redis 过期回调</strong></td><td style="text-align:left;"><code>keyspace notifications</code> 监听过期事件</td><td style="text-align:left;">简单</td><td style="text-align:left;">不可靠（Redis key 删除时才通知，可能漏）</td></tr><tr><td style="text-align:left;"><strong>定时任务轮询</strong></td><td style="text-align:left;">扫描待支付订单，到期更新状态</td><td style="text-align:left;">实现简单</td><td style="text-align:left;">数据量大时性能差，需要分批</td></tr><tr><td style="text-align:left;"><strong>Redisson 延迟队列</strong></td><td style="text-align:left;"><code>RDelayedQueue</code> 基于 Redis 实现</td><td style="text-align:left;">Java 生态友好</td><td style="text-align:left;">需要 Redisson</td></tr><tr><td style="text-align:left;"><strong>时间轮</strong></td><td style="text-align:left;">Netty HashedWheelTimer / Kafka 时间轮</td><td style="text-align:left;">高效</td><td style="text-align:left;">需要自己实现可靠性</td></tr></tbody></table><p><strong>推荐方案：</strong> RocketMQ 延时消息（18 个延时级别，如 level=16 对应 30min）+ 定时任务兜底扫表。</p><hr><h2 id="_5-亿级数据取出最大前-n-个" tabindex="-1">5. 亿级数据取出最大前 N 个 <a class="header-anchor" href="#_5-亿级数据取出最大前-n-个" aria-label="Permalink to &quot;5. 亿级数据取出最大前 N 个&quot;">​</a></h2><h3 id="小顶堆-单机" tabindex="-1">小顶堆（单机） <a class="header-anchor" href="#小顶堆-单机" aria-label="Permalink to &quot;小顶堆（单机）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 维护一个大小为 N 的小顶堆</span></span>
<span class="line"><span>2. 遍历所有数据</span></span>
<span class="line"><span>3. 如果当前元素 &gt; 堆顶，替换堆顶并调整堆</span></span>
<span class="line"><span>4. 遍历完成后，堆中就是最大的 N 个</span></span>
<span class="line"><span></span></span>
<span class="line"><span>时间复杂度：O(M × logN)，M 为数据总量</span></span>
<span class="line"><span>空间复杂度：O(N)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="分治-归并-大数据量" tabindex="-1">分治 + 归并（大数据量） <a class="header-anchor" href="#分治-归并-大数据量" aria-label="Permalink to &quot;分治 + 归并（大数据量）&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 分片：将数据分割，每片找到 Top N</span></span>
<span class="line"><span>2. 归并：将所有分片的 Top N 汇总，再取全局 Top N</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="mapreduce-超大" tabindex="-1">MapReduce（超大） <a class="header-anchor" href="#mapreduce-超大" aria-label="Permalink to &quot;MapReduce（超大）&quot;">​</a></h3><p>Map 阶段每个节点独立找 Top N，Reduce 阶段汇总取全局 Top N。</p><hr><h2 id="_6-如何设计一个秒杀系统" tabindex="-1">6. 如何设计一个秒杀系统？ <a class="header-anchor" href="#_6-如何设计一个秒杀系统" aria-label="Permalink to &quot;6. 如何设计一个秒杀系统？&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户请求 → CDN（静态资源）→ 限流 → 秒杀校验 → 异步下单</span></span>
<span class="line"><span>              │                  │         │          │</span></span>
<span class="line"><span>              ▼                  ▼         ▼          ▼</span></span>
<span class="line"><span>      减少服务器压力        防刷/防超     扣减库存   MQ异步处理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>核心设计：</strong></p><ol><li><strong>前端限流</strong> — 按钮置灰 + 验证码 + 答题</li><li><strong>网关层限流</strong> — Nginx 令牌桶/Sentinel 限流</li><li><strong>Redis 库存预扣减</strong> — Lua 脚本原子扣库存（比 DB 快 100 倍）</li><li><strong>异步下单</strong> — 扣库存成功后，通过 MQ 异步创建订单</li><li><strong>防超卖</strong> — Redis Lua 原子操作 + DB 乐观锁（version 字段）兜底</li><li><strong>流量削峰</strong> — MQ 排队下单，平滑后端处理压力</li><li><strong>降级兜底</strong> — 秒杀结束后显示&quot;已抢完&quot;</li></ol><h3 id="秒杀场景下如何增加库存" tabindex="-1">秒杀场景下如何增加库存？ <a class="header-anchor" href="#秒杀场景下如何增加库存" aria-label="Permalink to &quot;秒杀场景下如何增加库存？&quot;">​</a></h3><p>不建议在秒杀进行中增加库存（破坏公平性）。如果必须增加：</p><ol><li>暂停秒杀活动</li><li>运营后台同步增加 Redis 和 DB 中的库存数量</li><li>重新开放秒杀</li></ol>`,44)])])}const h=n(p,[["render",t]]);export{u as __pageData,h as default};
